import okhttp3.Interceptor
import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory

class NetworkModule {

    private val baseUrlMap = mapOf(
        "dev" to "https://api.dev.example.com/users",
        "staging" to "https://api.staging.example.com/users",
        "production" to "https://api.example.com/users"
    )

    private fun createOkHttpClient(token: String): OkHttpClient {
        val authInterceptor = Interceptor { chain ->
            val request = chain.request().newBuilder()
                .header("Authorization", "Bearer $token")
                .build()
            chain.proceed(request)
        }
        return OkHttpClient.Builder()
            .addInterceptor(authInterceptor)
            .build()
    }

    fun createRetrofitInstance(environment: String, token: String): Retrofit {
        val baseUrl = baseUrlMap[environment] ?: throw IllegalArgumentException("Invalid environment")
        val client = createOkHttpClient(token)
        return Retrofit.Builder()
            .baseUrl(baseUrl)
            .client(client)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }

    interface UserService {
        @GET("/")
        suspend fun fetchUsers(): List<User>
    }
}